parameters.jsCode:
return $input.all().map(i => {
  const j = i.json;
  return { json: {
    threadId: j.threadId,
    from: j.from?.value?.[0]?.address || j.From || '',
    subject: j.subject || j.Subject || '(no subject)',
    body: String(j.text || j.snippet || '').slice(0, 4000)
  } };
});

const out = [];
for (const item of $input.all()) {
  const txt = (item.json.content || []).filter(b => b.type === 'text').map(b => b.text).join('');
  let r;
  try { r = JSON.parse(txt.replace(/^```json?\s*|```\s*$/g, '')); }
  catch { r = { category: 'review', summary: txt.slice(0, 200), draft_reply: null }; }
  const src = $('Pack email').all()[item.pairedItem?.item ?? 0].json;
  if (r.draft_reply && (r.category === 'needs_reply' || r.category === 'urgent')) {
    out.push({ json: { ...src, ...r } });
  }
}
return out;

